function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; }
  catch (e) { return {}; }
}
function asArray(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(x => safeStr(x));
  if (typeof v === 'string' && v.trim()) {
    try { const p = JSON.parse(v); if (Array.isArray(p)) return p.filter(Boolean).map(x => safeStr(x)); } catch (e) {}
  }
  return [];
}

const row = $json;
const qaStage = safeStr(row.qaStage) || 'analyse';
const vorgangKey = safeStr(row.vorgangKey);

if (!vorgangKey) {
  return {
    json: {
      _qaAbort: true,
      passed: false,
      violations: [{ code: 'missing_vorgangKey', field: 'vorgangKey', message: 'Kein vorgangKey uebergeben - QA-Pruefung kann Zeile nicht zuordnen', severity: 'critical' }],
      hallucinationSuspects: [],
      sourceLockBreaches: [],
      qaStage,
      vorgangKey: '',
      vorgangsnummer: safeStr(row.vorgangsnummer),
      checkedAt: new Date().toISOString(),
      aiSkipped: true,
      skipAdversarialCheck: true
    }
  };
}

const analysis = parseObj(row.analysisJson);
const content = parseObj(row.contentJson);
const visual = parseObj(row.visualJson);

// SourceLock: kanonisch verschachtelt (analysisJson.sourceLock), Fallback auf P3b-Spiegelung (Top-Level row.sourceLock)
const rawSourceLock = (analysis.sourceLock && typeof analysis.sourceLock === 'object') ? analysis.sourceLock : parseObj(row.sourceLock);
const sourceLock = {
  sourceTopic: safeStr(rawSourceLock.sourceTopic),
  sourceConflict: safeStr(rawSourceLock.sourceConflict),
  requiredTerms: asArray(rawSourceLock.requiredTerms),
  requiredObjects: asArray(rawSourceLock.requiredObjects),
  requiredAction: safeStr(rawSourceLock.requiredAction),
  affectedGroups: asArray(rawSourceLock.affectedGroups),
  forbiddenDrift: asArray(rawSourceLock.forbiddenDrift)
};

// VisualAnchors: kanonisch verschachtelt, sonst Fallback auf flache Top-Level-Felder (P3b-Muster)
const rawAnchors = (analysis.visualAnchors && typeof analysis.visualAnchors === 'object') ? analysis.visualAnchors : {
  satireThemaKonkret: row.satireThemaKonkret,
  satireKonfliktKonkret: row.satireKonfliktKonkret,
  visualPflichtobjekte: row.visualPflichtobjekte,
  visualPflichthandlung: row.visualPflichthandlung,
  visualBetroffene: row.visualBetroffene,
  visualOrt: row.visualOrt,
  visualUeberzeichnung: row.visualUeberzeichnung,
  visualErkennungssatz: row.visualErkennungssatz,
  visualVerboteneErsatzmotive: row.visualVerboteneErsatzmotive
};
const visualAnchors = {
  satireThemaKonkret: safeStr(rawAnchors.satireThemaKonkret),
  satireKonfliktKonkret: safeStr(rawAnchors.satireKonfliktKonkret),
  visualPflichtobjekte: asArray(rawAnchors.visualPflichtobjekte),
  visualPflichthandlung: safeStr(rawAnchors.visualPflichthandlung),
  visualBetroffene: asArray(rawAnchors.visualBetroffene),
  visualOrt: safeStr(rawAnchors.visualOrt),
  visualUeberzeichnung: safeStr(rawAnchors.visualUeberzeichnung),
  visualErkennungssatz: safeStr(rawAnchors.visualErkennungssatz),
  visualVerboteneErsatzmotive: asArray(rawAnchors.visualVerboteneErsatzmotive)
};

// Zu pruefender Inhalt, je nach Stufe
let contentUnderReview = '';
if (qaStage === 'content') {
  contentUnderReview = [
    content.kernbotschaft,
    content.website && content.website.headline,
    content.website && content.website.article,
    content.facebook && content.facebook.post,
    content.instagram && content.instagram.caption,
    content.dieParteiReaktion && content.dieParteiReaktion.text,
    content.pressStatement
  ].map(safeStr).filter(Boolean).join('\n');
} else if (qaStage === 'visual_prompt') {
  contentUnderReview = [
    visual.imagePrompt,
    visual.altText,
    Array.isArray(visual.mustShow) ? visual.mustShow.join(', ') : '',
    visual.visibleAction,
    visual.recognitionSentence
  ].map(safeStr).filter(Boolean).join('\n');
} else {
  // 'analyse' / 'repair': keine generierte Prosa, nur Struktur pruefen
  contentUnderReview = [analysis.kurzfassung, analysis.satireBrief, asArray(analysis.satirePunchlines).join(' ')]
    .map(safeStr).filter(Boolean).join('\n');
}

const sourceFactsText = [safeStr(row.title), safeStr(row.summaryText), safeStr(row.combinedText)]
  .filter(Boolean).join('\n\n').slice(0, 6000);

return {
  json: {
    qaStage,
    vorgangKey,
    vorgangsnummer: safeStr(row.vorgangsnummer),
    title: safeStr(row.title),
    sourceLock,
    visualAnchors,
    contentUnderReview,
    sourceFactsText,
    skipAdversarialCheck: row.skipAdversarialCheck === true
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArray(v) { return Array.isArray(v) ? v.filter(Boolean).map(safeStr) : []; }

const d0 = $json;
if (d0._qaAbort) {
  return { json: d0 };
}

const sourceLock = d0.sourceLock || {};
const visualAnchors = d0.visualAnchors || {};
const qaStage = d0.qaStage;
const sourceFactsText = safeStr(d0.sourceFactsText);
const contentUnderReview = safeStr(d0.contentUnderReview);

function normalizeText(v) {
  return safeStr(v).toLowerCase()
    .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
}

const sourceNorm = normalizeText(sourceFactsText);

function sourceContainsExactTerm(term) {
  const n = normalizeText(term);
  if (!n || n.length < 3) return false;
  return sourceNorm.includes(n);
}

const genericObjectSet = new Set([
  'stadt', 'verwaltung', 'politik', 'buerokratie', 'gerechtigkeit',
  'haushalt', 'kosten', 'finanzierung', 'massnahme', 'verfahren',
  'gremium', 'beschluss', 'antrag', 'vorlage', 'thema', 'konflikt', 'situation',
  'problem', 'prioritaet', 'zustaendigkeit', 'planung', 'umsetzung'
].map(normalizeText));

const forbiddenSymbolRe = /\b(sparschwein|geldsack|waage|aktenberg|rathaus|nebel|monster|hai|haie|marionette|marionetten|theaterbuehne|theater|clown|clowns|maskottchen)\b/;

function isForbiddenSymbolObject(text) {
  const n = normalizeText(text);
  if (!n) return false;
  if (!forbiddenSymbolRe.test(n)) return false;
  return !sourceContainsExactTerm(text);
}

const sensitiveContextText = normalizeText([sourceFactsText, asArray(sourceLock.affectedGroups).join(' '), contentUnderReview].join(' '));
const sensitiveContext = /\b(minderjaehrig|minderjaehrige|kind|kinder|schueler|schuelerin|schuelerinnen|schuelern|behinderung|behindert|barrierefrei|barrierefreiheit|blind|blinde|blinder|sehbehindert|taub|krank|pflege|rollstuhl|gefluechtet|wohnungslos|obdachlos|armut|opfer|notlage)\b/.test(sensitiveContextText);

function isAllowedSensitiveSachobjekt(text) {
  const n = normalizeText(text);
  return /\b(lichtsignalanlage|ampel|signalanlage|signalgeber|akustischer signalgeber|taster|tasterkasten|taktile bodenplatten|bodenplatten|leitstreifen|rampe|rollstuhlrampe|barrierefreier zugang|barrierefreier taster|bordsteinabsenkung|massnahmenplan|fussgaengerfurt|fussgaengerueberweg|querung|verkehrsinsel)\b/.test(n);
}

function containsSensitivePerson(text) {
  const n = normalizeText(text);
  if (!n) return false;
  if (isAllowedSensitiveSachobjekt(n)) return false;
  return /\b(blinder|blinde|blindem|blinden|sehbehinderter|sehbehinderte|sehbehinderten|mensch mit behinderung|menschen mit behinderung|behinderter|behinderte|behinderten|schueler|schuelerin|schuelerinnen|schuelern|kind|kinder|minderjaehriger|minderjaehrige|patient|patientin|pflegebeduerftiger|pflegebeduerftige|rollstuhlfahrer|gefluechteter|gefluechtete|wohnungsloser|wohnungslose|obdachloser|obdachlose|kranker|kranke)\b/.test(n);
}

function containsSensitiveScene(text) {
  const n = normalizeText(text);
  if (!n || !sensitiveContext) return false;
  if (/\b(ein|eine|der|die|gruppe|gruppe von|mehrere|kleine gruppe)\s+(blinder|blinde|blindem|blinden|sehbehinderter|sehbehinderte|sehbehinderten|schueler|schuelerin|schuelerinnen|kind|kinder|rollstuhlfahrer|behinderte|behinderten)\b/.test(n)) return true;
  if (/\b(blinder|blinde|blinden|sehbehinderte|sehbehinderten|schueler|schuelerin|schuelerinnen|kind|kinder|rollstuhlfahrer|behinderte|behinderten)\b.{0,90}\b(tippt|drueckt|zeigt|stehen|steht|warten|wartet|laufen|laeuft|irren|irrt|suchen|sucht|stolpern|stolpert|queren|ueberqueren)\b/.test(n)) return true;
  if (/\b(blinde|blinder|blinden|sehbehinderte|schueler|kinder|rollstuhlfahrer|behinderte)\b.{0,120}\b(gefahr|gefaehrdet|verunsichert|hilflos|panik|panisch|unfall|verkehrschaos|risiko|dramatisch)\b/.test(n)) return true;
  return false;
}

function containsSensitiveMetaphor(text) {
  const n = normalizeText(text);
  if (!n || !sensitiveContext) return false;
  if (/\bblind(e|er|es|en)?\s+(sparschwein|haushalt|verwaltung|planung|politik|ampel|stadt|verfahren|rathaus)\b/.test(n)) return true;
  if (/\b(taub(e|er|es|en)?|lahm(e|er|es|en)?|krank(e|er|es|en)?|hilflos(e|er|es|en)?)\s+(verwaltung|planung|haushalt|politik|ampel|stadt|verfahren|rathaus)\b/.test(n)) return true;
  if (/barrierefreiheit.{0,60}\b(luxus|spass|teurer spass|uebertriebene forderung)\b/.test(n)) return true;
  return false;
}

function isConcreteObject(text) {
  const n = normalizeText(text);
  if (!n || n.length < 3) return false;
  if (genericObjectSet.has(n)) return false;
  if (isForbiddenSymbolObject(text)) return false;
  if (sensitiveContext && containsSensitivePerson(text)) return false;
  return true;
}
function concreteCount(arr) { return asArray(arr).filter(isConcreteObject).length; }

const STOP = new Set(['aber','alle','alles','auch','auf','aus','bei','das','dass','dem','den','der','des','die','dies','diese','einem','einen','einer','eine','eines','fuer','gegen','haben','hier','ihre','ihren','ist','kann','mit','nach','nicht','oder','sich','sind','soll','sollen','sowie','ueber','und','vom','von','vor','werden','wird','zur','zum']);
function tokens(value) { return normalizeText(value).replace(/[^a-z0-9\s]+/g, ' ').split(/\s+/).filter(t => t.length >= 4 && !STOP.has(t)); }
function stem(token) { const t = normalizeText(token).replace(/\s/g, ''); return t.length <= 5 ? t : t.substring(0, Math.max(5, Math.floor(t.length * 0.75))); }
function containsTerm(text, term) {
  const nt = normalizeText(text), nq = normalizeText(term);
  if (!nt || !nq) return false;
  if (nt.includes(nq)) return true;
  const compactText = nt.replace(/\s+/g, ''), compactTerm = nq.replace(/\s+/g, '');
  if (compactTerm.length >= 5 && compactText.includes(compactTerm)) return true;
  const tt = tokens(text), qt = tokens(term);
  if (!tt.length || !qt.length) return false;
  return qt.some(q => { const qs = stem(q); return tt.some(t => { const ts = stem(t); return t === q || ts === qs || (qs.length >= 5 && t.includes(qs)) || (ts.length >= 5 && q.includes(ts)); }); });
}
function relatedToAnchor(text, anchor) {
  const textTokens = tokens(text), anchorTokens = tokens(anchor);
  if (!textTokens.length || !anchorTokens.length) return false;
  let matches = 0;
  for (const a of anchorTokens) { const as = stem(a); if (textTokens.some(t => t === a || stem(t) === as || (as.length >= 5 && t.includes(as)))) matches++; }
  return matches >= (anchorTokens.length >= 4 ? 2 : 1);
}

function stemLight(w) {
  return w.replace(/(ungen|ierung|heit|keit|schaft|tion|ieren|iere|iert|ung|lich|isch|ische|ischen|ischer|isches)$/, '').replace(/(en|er|em|es|e|n|s|t)$/, '');
}
function tokenOverlap(a, b) {
  const tokensA = normalizeText(a).split(/[\W_]+/).filter(w => w.length >= 4).map(stemLight);
  const tokensB = normalizeText(b).split(/[\W_]+/).filter(w => w.length >= 4).map(stemLight);
  if (tokensA.some(w => tokensB.includes(w))) return true;
  const rawA = normalizeText(a).replace(/[\W_]+/g, ''), rawB = normalizeText(b).replace(/[\W_]+/g, '');
  for (const tok of tokensA) { if (tok.length >= 5 && rawB.includes(tok)) return true; }
  for (const tok of tokensB) { if (tok.length >= 5 && rawA.includes(tok)) return true; }
  return false;
}

const violations = [];

if (!sourceLock.sourceTopic) violations.push({ code: 'sourcelock_missing_topic', field: 'sourceLock.sourceTopic', message: 'sourceLock.sourceTopic fehlt', severity: 'high' });
if (!sourceLock.sourceConflict) violations.push({ code: 'sourcelock_missing_conflict', field: 'sourceLock.sourceConflict', message: 'sourceLock.sourceConflict fehlt', severity: 'high' });
if (asArray(sourceLock.requiredTerms).length < 2) violations.push({ code: 'sourcelock_few_terms', field: 'sourceLock.requiredTerms', message: 'sourceLock.requiredTerms enthaelt weniger als 2 Begriffe', severity: 'high' });
if (concreteCount(sourceLock.requiredObjects) < 2) violations.push({ code: 'sourcelock_few_objects', field: 'sourceLock.requiredObjects', message: 'sourceLock.requiredObjects enthaelt weniger als 2 konkrete Objekte', severity: 'high' });
if (!sourceLock.requiredAction) violations.push({ code: 'sourcelock_missing_action', field: 'sourceLock.requiredAction', message: 'sourceLock.requiredAction fehlt', severity: 'high' });

const hasAnchors = !!(visualAnchors.satireThemaKonkret || qaStage === 'visual_prompt');
if (hasAnchors) {
  if (!visualAnchors.satireThemaKonkret) violations.push({ code: 'anchors_missing_thema', field: 'visualAnchors.satireThemaKonkret', message: 'satireThemaKonkret fehlt', severity: 'medium' });
  if (!visualAnchors.satireKonfliktKonkret) violations.push({ code: 'anchors_missing_konflikt', field: 'visualAnchors.satireKonfliktKonkret', message: 'satireKonfliktKonkret fehlt', severity: 'medium' });
  if (concreteCount(visualAnchors.visualPflichtobjekte) < 2) violations.push({ code: 'anchors_few_objects', field: 'visualAnchors.visualPflichtobjekte', message: 'visualPflichtobjekte enthaelt weniger als 2 konkrete Objekte', severity: 'medium' });
  if (!visualAnchors.visualPflichthandlung) violations.push({ code: 'anchors_missing_handlung', field: 'visualAnchors.visualPflichthandlung', message: 'visualPflichthandlung fehlt', severity: 'medium' });
  if (!visualAnchors.visualErkennungssatz) violations.push({ code: 'anchors_missing_erkennungssatz', field: 'visualAnchors.visualErkennungssatz', message: 'visualErkennungssatz fehlt', severity: 'medium' });
  if (asArray(visualAnchors.visualVerboteneErsatzmotive).length < 2) violations.push({ code: 'anchors_few_forbidden', field: 'visualAnchors.visualVerboteneErsatzmotive', message: 'visualVerboteneErsatzmotive enthaelt weniger als 2 Eintraege', severity: 'medium' });
}

const guardScanText = [visualAnchors.visualPflichthandlung, visualAnchors.visualUeberzeichnung, visualAnchors.visualErkennungssatz, contentUnderReview].map(safeStr).join(' ');
const sensitivePersonObjects = [...asArray(visualAnchors.visualPflichtobjekte), ...asArray(sourceLock.requiredObjects)].filter(x => sensitiveContext && containsSensitivePerson(x));
if (sensitivePersonObjects.length > 0) violations.push({ code: 'guard_sensitive_object', field: 'visualPflichtobjekte/requiredObjects', message: 'Sensible Betroffene als Pflichtobjekt erkannt: ' + sensitivePersonObjects.join(', '), severity: 'critical' });
if (sensitiveContext && containsSensitiveScene(guardScanText)) violations.push({ code: 'guard_sensitive_scene', field: 'contentUnderReview', message: 'Sensible Betroffene erscheinen als Bildszene/Pointe', severity: 'critical' });
if (sensitiveContext && containsSensitiveMetaphor(guardScanText)) violations.push({ code: 'guard_sensitive_metaphor', field: 'contentUnderReview', message: 'Schutzlage wird als Metapher/Wortspiel verwendet', severity: 'critical' });
const forbiddenSymbols = [...asArray(visualAnchors.visualPflichtobjekte), ...asArray(sourceLock.requiredObjects)].filter(isForbiddenSymbolObject);
if (forbiddenSymbols.length > 0) violations.push({ code: 'guard_symbol_drift', field: 'visualPflichtobjekte/requiredObjects', message: 'Symbol-Drift erkannt: ' + forbiddenSymbols.join(', '), severity: 'high' });

if (contentUnderReview && (qaStage === 'content' || qaStage === 'visual_prompt')) {
  const concreteTerms = asArray(sourceLock.requiredTerms).filter(t => !genericObjectSet.has(normalizeText(t)));
  const requiredTermFound = concreteTerms.some(term => containsTerm(contentUnderReview, term));
  const sourceTopicFound = sourceLock.sourceTopic ? relatedToAnchor(contentUnderReview, sourceLock.sourceTopic) : false;
  const sourceConflictFound = sourceLock.sourceConflict ? relatedToAnchor(contentUnderReview, sourceLock.sourceConflict) : false;
  if (!(requiredTermFound || sourceTopicFound || sourceConflictFound)) {
    violations.push({ code: 'content_no_sourcelock_match', field: 'contentUnderReview', message: 'Generierter Inhalt enthaelt keinen erkennbaren Bezug zu sourceTopic, sourceConflict oder requiredTerms', severity: 'critical' });
  }
}

if (qaStage === 'visual_prompt') {
  const pflicht = asArray(visualAnchors.visualPflichtobjekte);
  if (pflicht.length >= 2 && contentUnderReview) {
    const covered = pflicht.filter(p => tokenOverlap(contentUnderReview, p));
    if (covered.length < 2) {
      violations.push({ code: 'visual_mustshow_mismatch', field: 'visual.mustShow', message: 'Bildinhalt deckt Pflichtobjekte nicht ab (gefunden: ' + covered.length + ' von ' + pflicht.length + ')', severity: 'high' });
    }
  }
}

const sourceLockBreachesDeterministic = violations.filter(v => v.code.indexOf('sourcelock_') === 0 || v.code === 'content_no_sourcelock_match' || v.code === 'visual_mustshow_mismatch');

return {
  json: {
    ...d0,
    deterministicViolations: violations,
    deterministicPassed: violations.length === 0,
    _sourceLockBreachesDeterministic: sourceLockBreachesDeterministic
  }
};

return {
  json: {
    ...$json,
    hallucinationSuspects: [],
    sourceLockDrift: [],
    aiSkipped: true,
    aiParseError: false
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArr(v) { return Array.isArray(v) ? v : []; }

function getAiText(j) {
  if (typeof j.content === 'string') return j.content;
  if (typeof j.text === 'string') return j.text;
  if (j.message && typeof j.message.content === 'string') return j.message.content;
  if (Array.isArray(j.choices) && j.choices[0] && j.choices[0].message) return safeStr(j.choices[0].message.content);
  return safeStr(JSON.stringify(j));
}

function extractJson(text) {
  const t = safeStr(text).replace(/```json/gi, '```').replace(/```/g, '');
  const start = t.indexOf('{');
  const end = t.lastIndexOf('}');
  if (start === -1 || end === -1 || end < start) return null;
  try { return JSON.parse(t.substring(start, end + 1)); } catch (e) { return null; }
}

const base = $('Deterministische Regelprüfung').item.json;
const aiText = getAiText($json);
const parsed = extractJson(aiText);

if (!parsed) {
  return {
    json: {
      ...base,
      hallucinationSuspects: [{ claim: '(KI-Pruefung nicht auswertbar)', whyProblematic: 'Antwort konnte nicht als JSON geparst werden', severity: 'unknown' }],
      sourceLockDrift: [],
      aiParseError: true,
      aiSkipped: false
    }
  };
}

return {
  json: {
    ...base,
    hallucinationSuspects: asArr(parsed.hallucinationSuspects),
    sourceLockDrift: asArr(parsed.sourceLockDrift),
    aiParseError: false,
    aiSkipped: false
  }
};

function asArr(v) { return Array.isArray(v) ? v : []; }

const d = $json;

if (d._qaAbort) {
  return { json: d };
}

const deterministicViolations = asArr(d.deterministicViolations);
const hallucinationSuspects = asArr(d.hallucinationSuspects);
const sourceLockDrift = asArr(d.sourceLockDrift);

const allViolations = [
  ...deterministicViolations,
  ...sourceLockDrift.map(x => ({ code: 'ai_sourcelock_drift', field: 'contentUnderReview', message: (x.claim || '') + ' - ' + (x.whyProblematic || ''), severity: x.severity || 'medium' }))
];

const passed = allViolations.length === 0 && hallucinationSuspects.length === 0;

const sourceLockBreaches = [
  ...asArr(d._sourceLockBreachesDeterministic),
  ...sourceLockDrift
];

return {
  json: {
    passed,
    violations: allViolations,
    hallucinationSuspects,
    sourceLockBreaches,
    qaStage: d.qaStage,
    vorgangKey: d.vorgangKey,
    vorgangsnummer: d.vorgangsnummer,
    checkedAt: new Date().toISOString(),
    aiSkipped: d.aiSkipped === true,
    aiParseError: d.aiParseError === true
  }
};

