// Bis dahin liefert dieser Platzhalter ein leeres KI-Ergebnis, damit der Rest des Workflows testbar bleibt.
return { json: { ...$json, content: JSON.stringify({ hallucinationSuspects: [], sourceLockDrift: [] }) } };
